def group_even_runs(nums: list[int]) -> list[list[int]]:
    if not nums:
        return []

    result = []
    current_run = []

    for num in nums:
        if num % 2 == 0:
            current_run.append(num)
        else:
            if current_run:
                result.append(current_run)
                current_run = []

    # Add the last run if any
    if current_run:
        result.append(current_run)

    return result
```
Example: `group_even_runs([2, 4, 7, 8, 10, 6])` → `[[2, 4], [8, 10, 6]]`

